			],
		},

	];

	const coreDomains = domains.filter(d => d.tier === 'core');
	const extendedDomains = domains.filter(d => d.tier !== 'core');

	function isActive(path: string): boolean {
		return page.url.pathname.startsWith(path);
	}

	function currentDomain(): string {
		const seg = page.url.pathname.split('/')[1];
		return domains.find(d => d.name === seg)?.label ?? '';
	}

	function currentEntity(): string {
		const segs = page.url.pathname.split('/');
		if (segs.length < 3) return '';
		const domain = domains.find(d => d.name === segs[1]);
		if (!domain) return '';
		const entity = domain.entities.find(e => e.path === `/${segs[1]}/${segs[2]}`);
